// Run Once for Each Item â€” n8n auto-splits Lever's top-level array
const posting = $input.item.json;
const company = $('Set Inputs').item.json;

if (posting?.error || !posting?.text) {
  return [];
}

const decodeEntities = (s) => String(s || '')
  .replace(/&amp;/g, '&')
  .replace(/&nbsp;/g, ' ')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'");

const stripHtml = (html) => decodeEntities(html)
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const isRemote = (p) => {
  const wp = String(p.workplaceType || '').toLowerCase();
  if (wp === 'remote') return true;
  const loc = String(p.categories?.location || '').toLowerCase();
  if (loc.includes('remote')) return true;
  const allLocs = Array.isArray(p.categories?.allLocations) ? p.categories.allLocations : [];
  return allLocs.some(l => String(l).toLowerCase().includes('remote'));
};

const normalizeEmploymentType = (commitment) =>
  String(commitment || '').toUpperCase().replace(/[-\s]/g, '');

const toIsoFromMs = (ms) => {
  if (!ms) return '';
  const d = new Date(Number(ms));
  return isNaN(d.getTime()) ? '' : d.toISOString();
};

// Lever splits JD content across description + lists + additional
const buildHtml = (p) => {
  const parts = [];
  if (p.description) parts.push(p.description);
  if (Array.isArray(p.lists)) {
    for (const list of p.lists) {
      const heading = list.text ? `<h3>${list.text}</h3>` : '';
      const body = list.content ? `<ul>${list.content}</ul>` : '';
      if (heading || body) parts.push(heading + body);
    }
  }
  if (p.additional) parts.push(p.additional);
  return decodeEntities(parts.join('\n'));
};

const buildPlainText = (p) => {
  const parts = [];
  if (p.descriptionPlain) parts.push(p.descriptionPlain);
  else if (p.description) parts.push(stripHtml(p.description));
  if (Array.isArray(p.lists)) {
    for (const list of p.lists) {
      if (list.text) parts.push(list.text);
      if (list.content) parts.push(stripHtml(list.content));
    }
  }
  if (p.additionalPlain) parts.push(p.additionalPlain);
  else if (p.additional) parts.push(stripHtml(p.additional));
  return parts.join(' ').replace(/\s+/g, ' ').trim();
};

const categories = posting.categories || {};
const allLocs = Array.isArray(categories.allLocations) ? categories.allLocations : [];
const location = String(categories.location || allLocs[0] || '').trim();

return {
  json: {
    _type: 'job',
    company: company.company_name,
    title: String(posting.text || '').trim(),
    url: String(posting.hostedUrl || posting.applyUrl || '').trim(),
    description_html: buildHtml(posting),
    description: buildPlainText(posting),
    location: location,
    remote: isRemote(posting),
    salary_text: '',
    employment_type: normalizeEmploymentType(categories.commitment),
    source: 'lever',
    posted_at: toIsoFromMs(posting.createdAt)
  }
};

const config = $('Trigger').first().json.config || {};
const watchlist = $('Trigger').first().json.watchlist || [];

const orderRaw = config.discovery_fetcher_order || '';
const enabledSources = String(orderRaw)
  .split(/[;,]/)
  .map(s => s.trim().toLowerCase())
  .filter(s => s.length > 0);

if (!enabledSources.includes('lever')) {
  console.log('[Lever] Disabled via discovery_fetcher_order â€” skipping');
  return [];
}

const thresholdRaw = Number(config.discovery_priority_threshold);
const priorityThreshold = isNaN(thresholdRaw) ? 999 : thresholdRaw;

const companies = watchlist
  .filter(c => {
    if (!c) return false;
    if (String(c.lever_slug || '').trim().length === 0) return false;
    const p = Number(c.priority);
    const priority = isNaN(p) ? 999 : p;
    return priority <= priorityThreshold;
  })
  .map(c => ({
    company_name: String(c.company_name || '').trim(),
    slug: String(c.lever_slug || '').trim()
  }));

if (companies.length === 0) {
  console.log(`[Lever] No companies match priority <= ${priorityThreshold} with lever_slug â€” skipping`);
  return [];
}

console.log(`[Lever] Fetching ${companies.length} boards (priority <= ${priorityThreshold})`);
return companies.map(c => ({ json: c }));

const company = $('Set Inputs').item.json;
const runId = $('Trigger').first().json.run_id || '';
const errPayload = $input.first().json || {};
const errObj = errPayload.error || {};

const statusCode = String(
  errObj.httpCode ||
  errObj.status ||
  errObj.cause?.response?.status ||
  ''
);
const message = String(errObj.message || 'Unknown error').substring(0, 500);

console.log(`[Lever] Fetch failed for ${company.company_name} (${company.slug}): ${statusCode} ${message}`);

return [{
  json: {
    _type: 'failure',
    run_id: runId,
    discovered_at: new Date().toISOString(),
    source: 'lever',
    company: company.company_name || '',
    slug: company.slug || '',
    status_code: statusCode,
    error_message: message
  }
}];
